- 'victorious teams' refers to the teams that were champions in a given season;
- 'years they won' refers to the year the championship season took place;
- 'games they played' refers to the total number of games played by the champion team during that particular championship season.

sql:
SELECT player_id, hits
FROM batting_stats
WHERE hits = (SELECT MAX(hits) FROM batting_stats);

SELECT COUNT(DISTINCT player_id)
FROM injuries
WHERE injury_date IS NOT NULL;

SELECT AVG(games_played) AS Average_Games_Played
FROM batting_stats
WHERE player_id = 1;

SELECT player_id, name, status, nationality, position
FROM players
WHERE status = 'active';
